var e=JSON.parse(`[{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"휴, 이걸로 청소 끝-","JPN":"ふう～これでお掃除完了！","ENG":"Whew, I'm finally done cleaning up.","TWN":"呼，都處理乾淨了-"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"이제 운동회가 방해 받을 일은 없으려나.","JPN":"もう運動会を邪魔する者はいないわよね。","ENG":"Now, I don't have to worry about them interfering with the Field Day.","TWN":"這下運動會應該不會受到影響了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"당신들도 걸을 수 있으면 이제 그만 돌아가.","JPN":"あなたたちも歩けるならそろそろ帰ってね。","ENG":"If you can walk, you'd better leave now.","TWN":"你們要是能走的話，現在也回去吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"근방에 있던 침식체들은 모두 처리했지만 잔류 침식파가 남아 있거든.","JPN":"近くにいた侵食体は全部片付けたけど、残留侵食波があるの。","ENG":"I took care of all the C.O.s around here, but their Corruption rays still remain.","TWN":"附近的侵蝕體雖然已經都處理掉了，但還殘留著侵蝕波。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L9_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"큰 문제는 없겠지만, 굳이 위험을 감수할 필요는 없잖아?","JPN":"大した問題はないけど、わざわざ危険な場所にいる必要はないでしょう？","ENG":"I doubt they'd cause you a serious problem, but you don't have to risk it, right?","TWN":"雖然應該沒什麼大問題，但也沒必要把自己放在危險裡吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"저기, 실례지만...... 당신은 카운터 아카데미의 학생으로 보이진 않는데요.","JPN":"あの、失礼ですが……あなたはカウンターアカデミーの生徒には見えませんね。","ENG":"Erm, I'm sorry, but you don't look like you're a student at the Counter Academy.","TWN":"那個，很抱歉……你看起來好像不是制裁者學院的學生。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"혹시 안전을 위해 고용된 용병 같은 겁니까?","JPN":"安全のために雇われた傭兵でしょうか？","ENG":"Are you a mercenary hired to secure the perimeter?","TWN":"難道是學院出於安全考慮雇傭的傭兵？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그런 건 아니야. 그냥 학생 보호자로 온 사람일 뿐이지.","JPN":"違うわ。生徒の保護者として来たの。","ENG":"Not exactly. I'm here with a student.","TWN":"不是，我就是一個學生的監護人。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L14_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"굳이 말하자면...... 학부모 같은 거려나?","JPN":"つまり……母親みたいな？","ENG":"Her chaperone, if you will.","TWN":"非要說的話……就是家長之類的？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"그, 그게 대체 무슨 뜻입니까?","JPN":"さ、さっぱりわかりませんが……","ENG":"W-what do you mean?","TWN":"你，你這話是什麼意思？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L17_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"평범한 학부모가 침식체들을 쓰러트릴 수 있을 리 없잖아요!","JPN":"普通の人が侵食体を倒せるなんて、あり得ません！","ENG":"There's no way an ordinary chaperone can defeat C.O.s like that!","TWN":"平凡的家長不可能打倒侵蝕體！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L18_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"애초에 여기서 왜 침식체가 나타난 건지 그 원인을 밝혀야 돼요.","JPN":"その前になぜここに侵食体が現れたのか原因を究明しないと！","ENG":"We must know why those C.O.s showed up to begin with.","TWN":"必須查明這裡一開始為什麼會出現侵蝕體。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L19_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"시청자들에겐 알 권리가 있으니까요!","JPN":"視聴者には知る権利があります！","ENG":"Our viewers have the right to know!","TWN":"觀眾們有權知道真相！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"응. 난 그런 얘기 잘 몰라.","JPN":"うーん、私ね、そういう話は詳しくないの。","ENG":"Well, I don't know what you're talking about.","TWN":"嗯，我不知道那些事。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L21_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그렇게 원인이 궁금하면 둘이 알아서 조사하도록 해.","JPN":"そんなに原因が知りたいなら二人で調査するといいわ。","ENG":"If you're so curious, good luck figuring it out between you two.","TWN":"想知道的話，你們兩個自己去調查吧。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"하지만 방송에서 내 얼굴이나 목소리가 나왔다간......","JPN":"でも放送に私の顔や声を流すつもりなら……","ENG":"But you'd better not show my face or play my voice on your show,","TWN":"不過如果電視上出現我的臉或者聲音……"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"알지?","JPN":"どうなるか、わかってるわよね？","ENG":"or...","TWN":"知道吧？"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_DESPAIR"},"R":null}},"sfx":"FX_COMBAT_ALL_MAGIC_SPELL_DARK_20"},{"id":"L24_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그 때는 침식체보다 무서운 학부모라는 게 어떤 뜻인지 가르쳐 줄게.","JPN":"その時は侵食体よりも怖い保護者がどんなものなのか、見せてあげるわ。","ENG":"I'll show you what I did to the C.O.s up close.","TWN":"到時候我會讓你們知道比侵蝕體更可怕的家長是什麼意思。"},"stage":{"bg":"BLACK","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L26_1","type":"dialog","speaker":"CAMERA_NPC_NULL_NULL","text":{"KOREA":"히익!","JPN":"ひいっ！","ENG":"Heek!","TWN":"啊啊！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L27_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"거, 걱정 마시죠! 저흰 여기서 아무것도 못 봤으니까요!","JPN":"ご、ご心配なく！　私たちはここで何も見ていません！","ENG":"D-don't worry! We saw nothing!","TWN":"別，別擔心！我們在這裡什麼都沒看到！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L28_1","type":"dialog","speaker":"REPORTER_NPC_NULL_NULL","text":{"KOREA":"카메라, 그렇지?","JPN":"カメラマンさんもそうだろ？","ENG":"Cameraman, right?","TWN":"攝影師，對吧？"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"CAMERA_NPC_NULL_NULL","text":{"KOREA":"네, 네에......! 그럼요! 그렇고 말고요!","JPN":"は、はい……！　もちろんです！　ええ、ごもっとも！","ENG":"Y-yes! Absolutely! We didn't see anything!","TWN":"是，是……！當然了！那是當然！"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 말을 잘 듣는 친구들이네.","JPN":"フフッ、イイ子ね。","ENG":"Hah hah. Smart choice.","TWN":"呵呵，很聽話嘛。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그럼 먼저 갈게. 우리 애들 도시락 챙겨 줄 시간이거든.","JPN":"では、お先に。子どもにお弁当を渡さなくちゃ。","ENG":"Then, if you'll excuse me. I have to go feed my kids lunch.","TWN":"那我先走了，因為我該給孩子們準備便當了。"},"stage":{"bg":"FOREST_NORMAL","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"아, 여기 있었네.","JPN":"ここにいたのね。","ENG":"Ah, there you are.","TWN":"啊，你在這兒呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}},"sfx":"FX_COMBAT_ALL_FOOT_STEP_LANDING_SMALL"},{"id":"L38_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"많이 기다렸지. 바쁜 일이 있어서 조금 늦었어.","JPN":"待たせてごめんなさい。ちょっと急用があって遅れちゃったわ。","ENG":"Sorry I kept you waiting. I had to take care of a few things first.","TWN":"你等很久了吧，因為要處理一些事，所以來晚了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......무슨 일로 온 거죠?","JPN":"……何しに来たんですか？","ENG":"What are you doing here?","TWN":"……你來幹什麼？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"작전 중에는 서로 간섭하지 않기로 했잖아요.","JPN":"作戦中はお互い干渉しないという約束でしたよね。","ENG":"This is not what we agreed upon.","TWN":"我們不是說好作戰時互不干涉嘛。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"저는 임무, 그쪽은 관광. 기억 안 나세요?","JPN":"私は任務、そちらは観光。覚えていませんか？","ENG":"I do the mission, and you do the tour. Don't you remember?","TWN":"我負責任務，你負責旅遊，我沒記錯吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L42_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그렇긴 하지만 점심시간인걸.","JPN":"でも今はランチタイムでしょ。","ENG":"But it's lunchtime.","TWN":"話雖如此，不過現在是午休時間嘛。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L43_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"여기, 도시락을 주려고 왔지.","JPN":"ほら、お弁当を渡したくて。","ENG":"Here, I've brought you your lunch.","TWN":"來，我給你送便當來了。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}},"sfx":"FX_CUTSCEN_NOISE_RUSTLE_02"},{"id":"L44_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"보온통에 담아 왔으니까 아직 따뜻할 거야.","JPN":"保温弁当箱に入れてきたからまだ温かいわよ。","ENG":"I used an insulated container. It should still be warm.","TWN":"我裝在保溫盒裡拿過來的，應該還熱的呢。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L45_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"도시락?","JPN":"お弁当を？","ENG":"Lunch?","TWN":"便當？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"}}}},{"id":"L46_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그냥 하는 말인 줄 알았는데...... 진짜 준비해 온 거에요?","JPN":"冗談かと思ったのに……本当に用意してきたんですか？","ENG":"I didn't know you really meant what you said.","TWN":"我以為你就是說說而已……你還真準備了？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L47_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"맞아. 하고 싶은 일은 다 하면서 후회 없이 살고 싶다고 했잖아.","JPN":"そうよ。やりたいことはやって、後悔しない生き方をしたいと言ったでしょ。","ENG":"I did. I told you, I don't want to leave any regrets.","TWN":"是啊，我不是說了嗎，我想活得無怨無悔，想做什麼就做什麼。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L48_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"오늘처럼 누군가를 위해 도시락을 준비할 기회는 자주 없으니까 말이야.","JPN":"今日みたいに誰かのためにお弁当を作る機会はあまりないから。","ENG":"It's not often that I get the chance to prepare lunch for someone.","TWN":"像今天這樣為某個人準備便當的機會可不常有。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L49_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"하지만 굳이 도시락을 쌀 필요는......","JPN":"でも、だからって手作りのお弁当を用意する必要は……","ENG":"But you didn't have to do this...","TWN":"其實沒必要準備便當……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L50_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"......부대에 발레리라는 애가 있었어.","JPN":"……部隊にヴァレリーという子がいたの。","ENG":"There was a kid named Valeriy in my squad.","TWN":"……部隊裡有個叫瓦萊里的孩子。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L4_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"......덩치에 안 맞게 군것질을 참 좋아했지.","JPN":"……おおきな体で、買い食いが大好きでね。","ENG":"He was a big boy, but he loved sweet desserts.","TWN":"……他的體格比較嬌小一點，卻很喜歡吃零食。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L5_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그런데 나는 보급도 책임져야 하니까......","JPN":"でも私は補給の責任者だったから……","ENG":"I was in charge of supplies then...","TWN":"不過我要負責補給……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L6_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"발레리가 숨겨 둔 간식들을 발견할 때마다 전부 압수했거든.","JPN":"ヴァレリーが隠していたおやつを見つけるたびに、全部取り上げたの。","ENG":"So I confiscated the cookies that Valeriy had hidden every time I found them.","TWN":"所以每次發現瓦萊里私藏零食，我都會全部沒收。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L7_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그런데...... 그 녀석이 나랑 제일 친한 친구를 구하려다 죽었어.","JPN":"なのに……あの子は私と一番仲のいい友達を助けるために死んでしまったの。","ENG":"And... he died trying to protect my best friend.","TWN":"可是……那孩子為了救我一個最好的朋友犧牲了。"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L8_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"CORRIDOR","bgm":"CUTSCENE_TALK_03","filter":"NCFT_SEPIA","slots":{"L":null,"C":{"char_id":"SHIELD_ADMIN_NAMED_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L11_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그냥 그런 생각이 들더라.","JPN":"あの時思ったわ。","ENG":"So I just thought...","TWN":"後來我就有了那樣的想法。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L12_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"살아 있을 때 맛있는 음식이라도 한 번 더 만들어 줄 걸, 하고.","JPN":"生きている間にもっと美味しい料理をたくさん作ってあげればよかった、と。","ENG":"I probably should have cooked delicious food for him while I had the chance.","TWN":"他活著的時候給他做一次好吃的料理該有多好啊。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L13_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그래서 만들어 봤어. 음식 솜씨를 더 늘리려면 연습이 필요하잖아.","JPN":"だから作ってみたの。料理の腕を磨くには練習が必要でしょう。","ENG":"So I cooked. I need to practice to improve my cooking skills, you know.","TWN":"於是我就開始做料理了。多多練習才能提升手藝嘛。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L16_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......그럼 제가 요리 연습 상대라는 말이네요.","JPN":"……つまり、私は料理の練習相手ってことですね。","ENG":"You're saying you're practicing on me?","TWN":"……所以，我是你料理練習的對象囉。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L17_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"전 입맛이 까다롭다고 말씀 드렸을 텐데요?","JPN":"味にはうるさいと伝えたはずです。","ENG":"I told you I'm a picky eater.","TWN":"我之前好像說過我的口味很挑剔。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L18_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"으음, 그렇게 맛이 없진 않을 거라고 생각하는데?","JPN":"うーん、そんなにまずくはないと思うわ。","ENG":"Mm, I don't think this food tastes so terrible.","TWN":"呃嗯，我覺得不會那麼難吃吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L19_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"나, 손재주가 좋은 편이거든.","JPN":"これでも、手際はいいほうなんだから。","ENG":"I'm pretty good with my hands.","TWN":"我，手藝應該…還是挺不錯的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L20_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그리고 듣자하니 너도 <color=#ffd34c>학교</color>에 좋은 추억은 없다면서?","JPN":"聞いた話だとあなたも<color=#ffd34c>学校</color>にはいい思い出がないのでしょう？","ENG":"And I've heard you don't have many good memories of your <color=#ffd34c>school</color>.","TWN":"而且我聽說，你在<color=#ffd34c>學校</color>也沒什麼好的回憶？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L21_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그렇죠. 제가 다녔던 학교는 리플레이서 신디케이트의 실험체 연구소였으니까요.","JPN":"そうですね。私が通っていた学校はリプレイサー・シンジケートの実験体研究所だったので。","ENG":"I don't. The school I went to was the Replacer Syndicate's lab, where they conducted experiments on human subjects.","TWN":"沒錯。我就讀的學校是克隆集團的實驗體研究所。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L22_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"그럼 오늘을 기회로 삼아서 하나 만들어 보면 어때?","JPN":"じゃあ、せっかくいい機会なのだし、思い出を作ってみたらどう？","ENG":"Then, why don't you make one good memory today?","TWN":"那你就把今天當成一個機會，製造一個美好的回憶怎麼樣？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L23_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"운동회에서 먹는 도시락은 분명 좋은 기억으로 남을 거야.","JPN":"運動会で食べるお弁当はきっと楽しい思い出になるわ。","ENG":"I bet eating lunch on a Field Day will help you create some fond memories.","TWN":"在運動會上吃便當一定會成為美好回憶的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"}}}},{"id":"L24_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_DESPAIR"}}}},{"id":"L26_1","type":"dialog","speaker":"GIRL_NPC_NULL_Q","text":{"KOREA":"알렉스 씨! 친구들을 데려왔어요!","JPN":"アレックスさん！　友達を連れてきました！","ENG":"Alex! I've brought my friends!","TWN":"雅蕾克絲！我帶朋友們過來了！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":null,"R":null}}},{"id":"L27_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 초대 손님들이 도착했네. 잘 왔어.","JPN":"フフッ、可愛いお客さんたちも来たわね。","ENG":"Hah hah. The guests have arrived. Welcome, kids.","TWN":"呵呵，客人們也都到了呢，來得正好。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L29_1","type":"dialog","speaker":"POLEARM_JUNIOR_NULL_NULL","text":{"KOREA":"처, 처음 뵙겠습니다. 케이시라고 해요......","JPN":"は、はじめまして。ケイシーです……","ENG":"N-nice to meet you. My name is Kaci.","TWN":"初，初次見面，請多關照，我叫卡西……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"POLEARM_JUNIOR_NULL_NULL","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L30_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"안녕, 케이시? 이리 와서 앉으렴?","JPN":"はじめまして、ケイシー。さあ、ここに座ってちょうだい。","ENG":"Hello, Kaci. Why don't you come over here and have a seat?","TWN":"你好，卡西？過來坐吧？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_LAUGH"},"R":null}}},{"id":"L31_1","type":"dialog","speaker":"SPEAKER_JUNIOR_NULL_BLUE","text":{"KOREA":"그럼 신세 좀 질게! 뇌를 활성화 하려면 영양분이 많이 필요하거든!","JPN":"それじゃあ、お邪魔するね！　脳の活性化には栄養分がたくさん必要なんだ！","ENG":"Thank you for the invitation! My brain needs lots of nutrients to stay active.","TWN":"那我就不客氣了！要想保持大腦清楚，需要大量的營養成分！"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SPEAKER_JUNIOR_NULL_BLUE","face":"UNIT_IDLE"},"R":null}}},{"id":"L32_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"얼마든지 괜찮아. 음식은 충분히 만들어 뒀으니까.","JPN":"遠慮なくどうぞ。料理ならたくさん作っておいたの。","ENG":"Be my guest. I've got plenty of food to go around.","TWN":"隨便吃，一定都夠。食物很充足。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L34_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"이 애들은......","JPN":"この子たちは……","ENG":"These kids...","TWN":"這些孩子是……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L36_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"여기서 알게 된 애들이야. 새로 사귄 친구들이라고 해도 괜찮으려나.","JPN":"ここで知り合ったのよ。新しいお友達と言ってもいいかしら？","ENG":"I met them here. They're my new friends.","TWN":"都是我在這裡認識的孩子，也可以說是新結交的朋友。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L37_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"할 수 있다면 여럿이 모여서 먹는 편이 화목한 가족 같아서 좋잖아?","JPN":"できれば大勢で集まって食べたほうが、和やかな家族みたいでいいじゃない？","ENG":"I thought it'd be nice to eat together, like a happy family would.","TWN":"大家坐在一起吃就好像和睦的大家庭，不是嗎？"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"R":null}}},{"id":"L39_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"......","JPN":"……","ENG":"......","TWN":"……"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SURPRISE"},"R":null}}},{"id":"L40_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"확실히 이렇게 함께 나누는 식사가 즐겁긴 하죠.","JPN":"確かに、こうやってみんなで一緒に食べる食事は楽しいですね。","ENG":"It's always nice to share a meal with people.","TWN":"跟大家一起吃東西果然很開心。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"},"R":null}}},{"id":"L41_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"그러니까 알렉스 씨도 같이 먹어요. ","JPN":"だからアレックスさんも一緒に食べましょう。","ENG":"So, why don't you join us, Alex? ","TWN":"所以雅蕾克絲你也一起吃吧。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":null,"C":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_IDLE"},"R":null}}},{"id":"L44_1","type":"dialog","speaker":"SEOYOON_ALT_SPORTS_NOBG","text":{"KOREA":"맛은 역시 좀 부족하지만요.","JPN":"やっぱり味はちょっと微妙ですけど。","ENG":"The food could use some improvement, though.","TWN":"味道還是差了一點點。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}},{"id":"L45_1","type":"dialog","speaker":"GSWORD_ADMIN_SPORTS_NULL","text":{"KOREA":"후훗. 기준이 높다더니 정말이네. 다음엔 더 정성 들여 만들어 줄게.","JPN":"フフッ、味にうるさいのは本当みたいね。今度はもっと心を込めて作ってあげるわ。","ENG":"Hah hah. You really are a picky eater, aren't you? Okay, I'll try harder next time.","TWN":"呵呵，你的標準倒是真高啊。下次我會再努力的。"},"stage":{"bg":"SPORTSGROUND","bgm":"CUTSCENE_TALK_03","filter":"NCFT_NORMAL","slots":{"L":{"char_id":"GSWORD_ADMIN_SPORTS_NULL","face":"UNIT_IDLE"},"C":null,"R":{"char_id":"SEOYOON_ALT_SPORTS_NOBG","face":"UNIT_SERIOUS"}}}}]`);export{e as default};